<?php
 namespace WPAICG\AutoGPT\Cron\EventProcessor\Trigger; use WPAICG\AutoGPT\Cron\AIPKit_Automated_Task_Content_Queuer; if (!defined('ABSPATH')) { exit; } function trigger_content_indexing_task_logic(int $task_id, array $task_config, ?string $last_run_time): void { if (isset($task_config['index_existing_now_flag']) && $task_config['index_existing_now_flag'] === '1') { AIPKit_Automated_Task_Content_Queuer::maybe_queue_initial_indexing_content($task_id, $task_config, false); } if (isset($task_config['only_new_updated_flag']) && $task_config['only_new_updated_flag'] === '1') { AIPKit_Automated_Task_Content_Queuer::queue_new_or_updated_indexing_content($task_id, $task_config, $last_run_time); } } 